import React from 'react';
import Container from '../atoms/Container';

export type BlogProps = { title?: string; description?: string; date?: string };

const Blog: React.FC<BlogProps> = ({
  title = '',
  description = '',
  date = ''
}) => {
  return (
    <div className="border-b border-gray-300 py-8">
      <Container>
        <h2 className="text-3xl mb-4 font-bold">{title}</h2>
        {description.length > 0 && <p className="mb-4">{description}</p>}
        {date.length > 0 && <p className="text-gray-500">Posted: {date}</p>}
      </Container>
    </div>
  );
};

Blog.displayName = 'Blog';
Blog.defaultProps = { title: '', description: '', date: '' };

export default Blog;
